import { readFile, unlink, writeFile } from 'node:fs/promises';

const astTypesPath = new URL('../out/language/generated/ast.d.ts', import.meta.url);
const cjsTypesPath = new URL('../out/index.d.cts', import.meta.url);
const staleSourceMapPath = new URL('../out/index.d.cts.map', import.meta.url);

const astTypes = await readFile(astTypesPath, 'utf-8');
const inlinedAstTypes = astTypes
    .split('\n')
    .filter(line => !line.startsWith('import ') && !line.startsWith('//# sourceMappingURL='))
    .join('\n')
    .trim();

const cjsTypes = `/**
 * CommonJS declaration entry for the bundled livex API.
 * This file is generated by scripts/emit-cjs-types.mjs.
 */

interface AstNode {
    readonly $type: string;
    readonly $container?: AstNode;
}

interface Reference<T = AstNode> {
    readonly ref?: T;
    readonly $refText: string;
    readonly error?: {
        message: string;
        [property: string]: unknown;
    };
}

interface ReferenceInfo {
    readonly reference?: Reference;
    readonly container?: AstNode;
    readonly property?: string;
    readonly index?: number;
    [property: string]: unknown;
}

interface TypeMetaData {
    [property: string]: unknown;
}

declare abstract class AbstractAstReflection {
    abstract getAllTypes(): string[];
    isSubtype(subtype: string, supertype: string): boolean;
    abstract getReferenceType(refInfo: ReferenceInfo): string;
    abstract getTypeMetaData(type: string): TypeMetaData;
}

interface LangiumDocument<T = AstNode> {
    parseResult: {
        value: T;
        parserErrors: LivExParserError[];
        lexerErrors?: unknown[];
    };
    diagnostics?: LivExDiagnostic[];
    [property: string]: unknown;
}

${inlinedAstTypes}

export type LivExServices = Record<string, unknown>;

export interface ExecRequest {
    [exampleName: string]: ExecRequestExample;
}

export interface ExecRequestExample {
    method: string;
    args: Array<number | string>;
    probes: ExecRequestProbe[];
}

export interface ExecRequestProbe {
    line: number;
    expr: {
        target: string;
        lang: string;
        scopes: string[];
    };
    condition: string;
}

export type LivExParserError = {
    message: string;
    [property: string]: unknown;
};

export type LivExDiagnostic = {
    message: string;
    [property: string]: unknown;
};

export interface ParseLivExOptions {
    services?: LivExServices;
    documentUri?: string;
    validation?: boolean;
}

export interface ParseLivExResult {
    ast: DefinitionList;
    document: LangiumDocument<DefinitionList>;
    parserErrors: LivExParserError[];
    diagnostics: LivExDiagnostic[];
}

export interface ParseLivExAstOptions {
    services?: LivExServices;
    throwOnParserErrors?: boolean;
}

export declare function createLivExServices(context: unknown): {
    shared: unknown;
    LivEx: LivExServices;
};
export declare function parseLivEx(code: string, options?: ParseLivExOptions): Promise<ParseLivExResult>;
export declare function parseLivExAst(code: string, options?: ParseLivExAstOptions): DefinitionList;
export declare function execRequestAction(code: string, options?: ParseLivExAstOptions): ExecRequest;
`;

await writeFile(cjsTypesPath, cjsTypes);
await unlink(staleSourceMapPath).catch(error => {
    if (error.code !== 'ENOENT') {
        throw error;
    }
});
